import streamlit as st
from src.components.header import header_home
from src.ui.style_base_layout import style_base_layout,style_background_home,style_base_dashboard

def home_screen():

    
    header_home()
    style_background_home()
    style_base_layout() 


    st.write("Please select your login type to continue.")

    col1, col2 = st.columns(2)
    with col1:
        st.header("I am Teacher")
        st.image("https://img.freepik.com/free-vector/indonesian-female-civil-servant-holding-pen-book_10045-780.jpg?semt=ais_hybrid&w=740&q=80", width= 120)
        if st.button("Login as Teacher", type='primary'):
            st.session_state['login_type'] = 'teacher'
            st.rerun()
    with col2:
        st.header("I am Student")
        st.image("data:image/jpeg;base64,",width= 120)
        if st.button("Login as Student", type='primary'):
            st.session_state['login_type'] = 'student'
            st.rerun()
        
            